// Packet Fabric (Vertical) -- advect each packet DOWN an assigned vertical link, recycle at the bottom.
// uFlow  = (flowSpeed, linkCount, curveAmount, time)
// uClock = (ptpRate, fieldScale, streams, jitter)
// Uniforms are AUTO-declared from the Vectors page -- do NOT redeclare here.

float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }
vec3  hash31(float p){ return fract(sin(vec3(p*127.1, p*311.7, p*74.7))*43758.5453)*2.0-1.0; }

// a node anchor; senders live near the TOP (+Y), receivers near the BOTTOM (-Y).
vec3 nodeAnchor(float n, float scale, float yLevel){
    vec3 h = hash31(n*13.0 + 1.0);
    // spread nodes mostly along X (a tall portrait field), fixed Y level, small Z scatter
    return vec3(h.x*0.9*scale, yLevel, h.z*0.5*scale);
}

void main(){
    const uint id = TDIndex();
    if(id >= TDNumElements()) return;

    float t      = uFlow.w;
    float speed  = uFlow.x;
    float linkN  = max(2.0, uFlow.y);
    float curve  = uFlow.z;
    float scale  = uClock.y;
    float jitter = uClock.w;

    float pid = float(id);

    // assign this packet to a vertical link (a top sender + a bottom receiver)
    float link    = floor(mod(pid, linkN));
    float srcNode = floor(mod(link*2.0,   linkN+7.0));
    float dstNode = floor(mod(link*2.0+1.0, linkN+11.0));
    vec3  A = nodeAnchor(srcNode, scale,  1.7*scale);   // sender (top)
    vec3  B = nodeAnchor(dstNode, scale, -1.7*scale);   // receiver (bottom)

    // a gentle horizontal control point so the link bows (fiber slack)
    vec3  mid = mix(A, B, 0.5);
    vec3  bow = vec3((hash11(link*7.3)*2.0-1.0)*1.0, 0.0, (hash11(link*3.1)*2.0-1.0)*0.6) * curve;
    vec3  C   = mid + bow;

    // per-packet parametric position: travels DOWN the link (s: 0 top -> 1 bottom), wraps.
    float jit = (hash11(pid*1.7)*2.0-1.0) * 0.08 * jitter;
    float s   = fract(hash11(pid*9.13) + (t*speed*(0.6+0.5*hash11(pid*4.2))) + jit);

    // quadratic Bezier A(top) -> C -> B(bottom): s grows -> packet descends
    float u  = 1.0 - s;
    vec3 pos = u*u*A + 2.0*u*s*C + s*s*B;

    P[id] = pos;
}

// Packet Fabric (Vertical) -- per-packet stream color + PTP sync flash. (render side branch)
// uClock = (ptpRate, time, streams, pulseStrength)
// New attributes Color (vec4) and PointScale (float) come from the Attr sequence.
float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }

void main(){
    const uint id = TDIndex();
    if(id >= TDNumElements()) return;

    vec3 pos = TDIn_P(0, id);
    float pid = float(id);

    float streams = max(1.0, uClock.z);
    float klass   = floor(mod(pid, streams));   // 0=video,1=audio,2=ancillary

    vec3 cyan  = vec3(0.00, 0.90, 1.00);   // video essence
    vec3 green = vec3(0.22, 1.00, 0.42);   // audio essence
    vec3 amber = vec3(1.00, 0.69, 0.00);   // ancillary data
    vec3 col = (klass < 0.5) ? cyan : (klass < 1.5) ? green : amber;
    col = mix(col, vec3(1.0), 0.35);       // white-hot core lift; palette carries mid-glow

    // PTP grandmaster pulse: a steady beat all packets flash to, in lockstep.
    float rate  = max(0.05, uClock.x);
    float beat  = fract(uClock.y * rate);
    float flash = pow(max(0.0, 1.0 - beat*3.0), 3.0);
    float pulse = 1.0 + uClock.w * flash;

    Color[id]      = vec4(col * (0.45 * pulse), 1.0);
    PointScale[id] = 0.8 + 0.7*flash;      // packets swell on the sync beat
}

out vec4 fragColor;
void main(){
    vec2 uv = vUV.st * 2.0 - 1.0;
    float r = length(uv);
    float a = smoothstep(1.0, 0.05, r);   // bright round core, soft falloff edge
    a = pow(a, 1.5);
    fragColor = vec4(vec3(a), 1.0);
}

// Static vertical IP-fabric background: sender row (top) + receiver row (bottom) + faint vertical links.
// Cheap: a SMALL constant-bounded link loop (links are few), no per-pixel mass loop.
uniform vec4 uFab;   // x=linkCount, y=fieldScale, z=slowTime, w=ptpRate
out vec4 fragColor;
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
float segDist(vec2 p, vec2 a, vec2 b){
    vec2 pa=p-a, ba=b-a; float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0); return length(pa-ba*h);
}
void main(){
    vec2 uv = vUV.st;
    float aspect = uTDOutputInfo.res.z / uTDOutputInfo.res.w;
    vec2 p = (uv - 0.5); p.x *= aspect;     // centered, y up

    vec3 col = mix(vec3(0.012,0.014,0.018), vec3(0.026,0.030,0.038), 1.0-length(p));

    float linkN = clamp(uFab.x, 4.0, 24.0);
    vec3 fiber = vec3(0.0);
    const int MAXL = 24;
    for(int i=0;i<MAXL;i++){
        if(float(i) >= linkN) break;
        float fi = float(i);
        // sender near the top, receiver near the bottom -> VERTICAL links
        vec2 a = vec2((hash21(vec2(fi,1.0))-0.5)*0.9*aspect,  0.42);  // top
        vec2 b = vec2((hash21(vec2(fi,3.0))-0.5)*0.9*aspect, -0.42);  // bottom
        float d = segDist(p, a, b);
        fiber += vec3(0.10,0.13,0.16) * smoothstep(0.010, 0.0, d) * 0.5;
        float tw = 0.7 + 0.3*sin(uFab.z*6.2831 + fi*2.0);
        fiber += vec3(0.12,0.16,0.20) * smoothstep(0.045,0.0,length(p-a)) * tw;  // sender node
        fiber += vec3(0.12,0.16,0.20) * smoothstep(0.045,0.0,length(p-b)) * tw;  // receiver node
    }
    col += fiber;

    // depth haze: dim toward the frame edges
    col *= mix(1.0, 0.55, smoothstep(0.4, 1.1, length(p)));
    // grain to kill banding on the dark gradient at booth scale
    col += (hash21(uv*uTDOutputInfo.res.zw + uFab.z*100.0) - 0.5) * 0.012;
    fragColor = vec4(max(col, 0.0), 1.0);
}

// Bright-pass + gaussian blur at 1/4 resolution. The 4K-safe replacement for a full-res tap loop.
uniform vec4 uBloom;   // x=strength, y=threshold, z=blurWidth
out vec4 fragColor;
void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;   // 1/lowW, 1/lowH (large in screen terms)
    float thr = uBloom.y;
    float bw  = uBloom.z;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 6;                     // 13x13 taps but only on ~1/16 the pixels
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/22.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*bw).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    fragColor = vec4((sum/max(wsum,1e-4)) * uBloom.x, 1.0);
}
